import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { AuthService, EnrollmentService, ExamsService, LiveSessionsService } from '../../services';
import { Enrollment, Exam, LiveSession } from '../../models';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss']
})
export class DashboardComponent implements OnInit {
  user = this.authService.currentUser;
  enrollments: Enrollment[] = [];
  upcomingExams: Exam[] = [];
  upcomingSessions: LiveSession[] = [];
  loading = true;

  constructor(
    private authService: AuthService,
    private enrollmentService: EnrollmentService,
    private examsService: ExamsService,
    private liveSessionsService: LiveSessionsService
  ) {}

  ngOnInit() {
    this.loadDashboardData();
  }

  loadDashboardData() {
    this.enrollmentService.getEnrollments().subscribe(enrollments => {
      this.enrollments = enrollments;
    });

    this.examsService.getExams().subscribe(exams => {
      this.upcomingExams = exams.filter(exam => 
        exam.scheduledAt && new Date(exam.scheduledAt) > new Date()
      );
    });

    this.liveSessionsService.getLiveSessions(true).subscribe(sessions => {
      this.upcomingSessions = sessions;
      this.loading = false;
    });
  }

  get userInitials(): string {
    if (!this.user) return '';
    return `${this.user.firstName.charAt(0)}${this.user.lastName.charAt(0)}`.toUpperCase();
  }

  get welcomeMessage(): string {
    const hour = new Date().getHours();
    if (hour < 12) return 'Good morning';
    if (hour < 18) return 'Good afternoon';
    return 'Good evening';
  }
}
<div class="min-h-screen bg-gray-50 py-8">
  <div class="max-w-7xl mx-auto px-4">
    <!-- Welcome Header -->
    <div class="bg-white rounded-lg shadow-lg p-6 mb-8">
      <div class="flex items-center justify-between">
        <div>
          <h1 class="text-3xl font-bold text-gray-900 mb-2">
            {{ welcomeMessage }}, {{ user?.firstName }}!
          </h1>
          <p class="text-gray-600">Welcome back to your learning dashboard</p>
        </div>
        <div class="flex items-center space-x-4">
          <div class="w-12 h-12 bg-gradient-to-r from-primary-600 to-pink-500 rounded-full flex items-center justify-center text-white font-semibold">
            {{ userInitials }}
          </div>
          <div>
            <div class="font-medium text-gray-900">{{ user?.firstName }} {{ user?.lastName }}</div>
            <div class="text-sm text-gray-500">{{ user?.role }}</div>
          </div>
        </div>
      </div>
    </div>

    <!-- Dashboard Grid -->
    <div class="grid md:grid-cols-2 gap-8">
      <!-- Enrolled Courses -->
      <div class="bg-white rounded-lg shadow-lg p-6">
        <h2 class="text-xl font-semibold text-gray-900 mb-4">My Courses</h2>
        <div class="space-y-4">
          <div *ngFor="let enrollment of enrollments" 
               class="flex items-center space-x-4 p-4 bg-gray-50 rounded-lg">
            <img [src]="enrollment.courseThumbnail || '/api/placeholder/100/100'" 
                 [alt]="enrollment.courseTitle" 
                 class="w-16 h-16 object-cover rounded-lg">
            <div class="flex-1">
              <h3 class="font-medium text-gray-900">{{ enrollment.courseTitle }}</h3>
              <div class="mt-2">
                <div class="text-sm text-gray-500 mb-1">Progress: {{ enrollment.progress }}%</div>
                <div class="w-full bg-gray-200 rounded-full h-2">
                  <div class="bg-gradient-to-r from-primary-600 to-pink-500 h-2 rounded-full transition-all duration-300"
                       [style.width]="enrollment.progress + '%'"></div>
                </div>
              </div>
            </div>
            <a [routerLink]="['/courses', enrollment.courseId]" 
               class="btn-gradient text-sm">
              Continue
            </a>
          </div>
        </div>
        <div *ngIf="enrollments.length === 0" class="text-center py-8 text-gray-500">
          No enrolled courses yet
        </div>
      </div>

      <!-- Upcoming Exams -->
      <div class="bg-white rounded-lg shadow-lg p-6">
        <h2 class="text-xl font-semibold text-gray-900 mb-4">Upcoming Exams</h2>
        <div class="space-y-4">
          <div *ngFor="let exam of upcomingExams" 
               class="p-4 bg-gray-50 rounded-lg">
            <h3 class="font-medium text-gray-900">{{ exam.title }}</h3>
            <div class="text-sm text-gray-500 mt-1">
              {{ exam.scheduledAt | date:'longDate' }} at {{ exam.scheduledAt | date:'shortTime' }}
            </div>
            <div class="text-sm text-gray-500">
              Duration: {{ exam.duration }} minutes • Questions: {{ exam.questionCount }}
            </div>
          </div>
        </div>
        <div *ngIf="upcomingExams.length === 0" class="text-center py-8 text-gray-500">
          No upcoming exams
        </div>
      </div>
    </div>

    <!-- Upcoming Live Sessions -->
    <div class="bg-white rounded-lg shadow-lg p-6 mt-8">
      <h2 class="text-xl font-semibold text-gray-900 mb-4">Upcoming Live Sessions</h2>
      <div class="grid md:grid-cols-3 gap-4">
        <div *ngFor="let session of upcomingSessions" 
             class="p-4 bg-gray-50 rounded-lg">
          <h3 class="font-medium text-gray-900 mb-2">{{ session.title }}</h3>
          <div class="text-sm text-gray-500 mb-2">{{ session.teacherName }}</div>
          <div class="text-sm text-gray-500">
            {{ session.scheduledAt | date:'longDate' }} at {{ session.scheduledAt | date:'shortTime' }}
          </div>
        </div>
      </div>
      <div *ngIf="upcomingSessions.length === 0" class="text-center py-8 text-gray-500">
        No upcoming live sessions
      </div>
    </div>
  </div>
</div>
